proof fn phi_1_combiner_request_ids_not_contains_external_body(
    combiners: Map<NodeId, CombinerState>,
    rid: ReqId,
)
    requires
        combiners.dom().finite(),
        combiner_request_id_fresh(combiners, rid),
    ensures
        !combiner_request_ids(combiners).contains(rid),
{
    combiner_request_ids_not_contains(combiners, rid);
}

proof fn phi_2_combiner_request_ids_finite_external_body(
    combiners: Map<NodeId, CombinerState>,
)
    requires
        combiners.dom().finite(),
    ensures
        combiner_request_ids(combiners).finite(),
{
    combiner_request_ids_finite(combiners);
}

proof fn phi_3_element_outside_set_external_body(s: Set<nat>)
    requires
        s.finite(),
    ensures ({
        let r = element_outside_set(s);
        !s.contains(r)
    }),
{
    let _ = element_outside_set(s);
}

proof fn phi_4_get_fresh_nat_always_exists(
    reqs: Set<ReqId>,
    combiner: Map<NodeId, CombinerState>,
)
    requires
        reqs.finite(),
        combiner.dom().finite(),
    ensures
        !reqs.contains(get_fresh_nat(reqs, combiner)),
        combiner_request_id_fresh(combiner, get_fresh_nat(reqs, combiner)),
{
    get_fresh_nat_not_in(reqs, combiner);
}

proof fn phi_5_get_fresh_nat_closed_spec_choose(
    reqs: Set<ReqId>,
    combiner: Map<NodeId, CombinerState>,
    reqs2: Set<ReqId>,
)
    requires
        reqs.finite(),
        reqs2.finite(),
        combiner.dom().finite(),
        reqs.subset_of(reqs2),
    ensures
        !reqs2.contains(get_fresh_nat(reqs, combiner)) || !reqs.contains(get_fresh_nat(reqs2, combiner)),
{
    get_fresh_nat_not_in(reqs, combiner);
    get_fresh_nat_not_in(reqs2, combiner);
}
